import { useState, useEffect } from 'react'
import Header from './components/Header'
import Hero from './components/Hero'
import About from './components/About'
import Projects from './components/Projects'
import Skills from './components/Skills'
import Contact from './components/Contact'
import Footer from './components/Footer'
import {
  portfolioAPI,
  projectsAPI,
  skillsAPI,
  contactAPI,
} from './api'

function App() {
  const [portfolioData, setPortfolioData] = useState(null)
  const [projects, setProjects] = useState([])
  const [skills, setSkills] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)

  useEffect(() => {
    fetchData()
  }, [])

  const fetchData = async () => {
    try {
      setLoading(true)
      const [portfolio, projectsData, skillsData] = await Promise.all([
        portfolioAPI.getPortfolio(),
        projectsAPI.getAllProjects(),
        skillsAPI.getAllSkills(),
      ])
      setPortfolioData(portfolio)
      setProjects(projectsData)
      setSkills(skillsData)
    } catch (err) {
      console.error('Error fetching data:', err)
      setError(err.message)
    } finally {
      setLoading(false)
    }
  }

  const handleNavigate = (href) => {
    const element = document.querySelector(href)
    if (element) {
      element.scrollIntoView({ behavior: 'smooth' })
    }
  }

  const handleContactSubmit = async (formData) => {
    return await contactAPI.submitContact(formData)
  }

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-50 via-white to-purple-50">
        <div className="text-center">
          <div className="animate-spin rounded-full h-16 w-16 border-b-2 border-blue-600 mx-auto mb-4" />
          <p className="text-gray-600">Loading portfolio...</p>
        </div>
      </div>
    )
  }

  if (error) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-50 via-white to-purple-50">
        <div className="text-center">
          <p className="text-red-600 mb-4">Error loading portfolio: {error}</p>
          <button
            onClick={fetchData}
            className="px-6 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
          >
            Retry
          </button>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen">
      <Header onNavigate={handleNavigate} />
      <Hero onContact={() => handleNavigate('#contact')} />
      <About portfolioData={portfolioData} />
      <Projects projects={projects} />
      <Skills skills={skills} />
      <Contact onContactSubmit={handleContactSubmit} />
      <Footer />
    </div>
  )
}

export default App
